import React, { useEffect, useState } from 'react'
import {
    Row,
    Col,
    Button,
    Space,
    Input,
    Modal,
    Checkbox,
    Select,
    Form,
    DatePicker,
    Divider,
    Radio
} from 'antd';

import dashToSpace from '../../../../../helpers/dashToSpace'

const { RangePicker } = DatePicker
const { Option } = Select

const CheckboxSignatureContent = () => {
    return (
        <div>
            <Form.Item label="Tempat dan Tanggal"
                name="year"
                rules={[{ required: false }]}
            >
                <Input />
            </Form.Item>

            <Form.Item label="Penanggung Jawab"
                name="year"
                rules={[{ required: false }]}
            >
                <Select placeholder="Select province">
                    <Option value="Zhejiang">Asc</Option>
                    <Option value="Jiangsu">Desc</Option>
                </Select>
            </Form.Item>
        </div>
    )
}

const ModalCetak = (props) => {

    const [isLoading, setIsLoading] = useState(false)
    const [showCheckboxSignatureContent, setShowCheckboxSignatureContent] = useState(false)

    const handleCheckboxAddSignature = (e) => {
        console.log(`checked = ${e.target.checked}`);
        e.target.checked ? setShowCheckboxSignatureContent(true) : setShowCheckboxSignatureContent(false)
    }

    //cancel handle in modal
    const handleOk = (e) => {
        setIsLoading(true)
    }
    //cancel handle in modal
    const handleCancel = (e) => {
        props.handleCloseModal(false)
    }

    // console.log('visibleModal', visibleModal)

    return (
        <Modal
            visible={props.visibleModal}
            title={[`Cetak inventaris ${dashToSpace(props.location.pathname.split('/').slice(0,-2).pop())}`]}
            onOk={handleOk}
            onCancel={handleCancel}
            width={1000}
            footer={false}
        >
            <Form name="complex-form" labelCol={{ span: 4 }} wrapperCol={{ span: 18 }}>
                <Form.Item label="Kode Alat">
                    <Input />
                </Form.Item>
                <Form.Item label="Nama Alat">
                    <Input />
                </Form.Item>

                <Form.Item label="Gedung"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Lantai"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Ruangan"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Status"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Level Resiko"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Kondisi"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Zhejiang</Option>
                        <Option value="Jiangsu">Jiangsu</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Tanggal Beli"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <RangePicker
                        style={{width: '100%'}}
                        placeholder={['Tanggal Awal', 'Tanggal Akhir']} />
                </Form.Item>

                <Form.Item label="Order"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Select placeholder="Select province">
                        <Option value="Zhejiang">Asc</Option>
                        <Option value="Jiangsu">Desc</Option>
                    </Select>
                </Form.Item>

                <Form.Item label="Tanda Tangan"
                    name="year"
                    rules={[{ required: false }]}
                >
                    <Checkbox onChange={handleCheckboxAddSignature} />
                </Form.Item>

                {
                    showCheckboxSignatureContent ? <CheckboxSignatureContent /> : null
                }

                <Form.Item label="Jenis laporan"
                    rules={[{ required: false }]}>
                    <Radio.Group name="radiogroup" defaultValue={1}>
                        <Radio value={1}>Umum</Radio>
                        <Radio value={3}>ASPAK</Radio>
                        <Radio value={2}>Summary</Radio>
                    </Radio.Group>
                </Form.Item>

                <Form.Item label="Cetak dalam format"
                    rules={[{ required: false }]}>
                    <Radio.Group name="radiogroup" defaultValue={1}>
                        <Radio value={1}>PDF</Radio>
                        <Radio value={2}>Excel</Radio>
                    </Radio.Group>
                </Form.Item>

                <Form.Item label={" "}>
                    <Space>
                        <Button type="primary" loading={isLoading} onClick={handleOk}>
                            Cetak
                        </Button>
                        <Button onClick={handleCancel}>
                            Batal
                        </Button>
                    </Space>
                </Form.Item>
            </Form>
        </Modal>
    )

}

export default ModalCetak